import WebSocket, { WebSocketServer } from 'ws';

const wss = new WebSocketServer({ port: 8080 });

wss.on('connection', (ws: WebSocket) => {
  console.log('A client connected');

  ws.on('message', (message: string) => {
    console.log(`Received: ${message}`);
    // Broadcast received message to all clients
    wss.clients.forEach(client => {
      if (client !== ws && client.readyState === WebSocket.OPEN) {
        client.send(message);
      }
    });
  });

  ws.on('close', () => {
    console.log('A client disconnected');
  });
});

console.log('WebSocket server running on ws://localhost:8080/');

type NetworkError = {
  type: 'network';
  message: string;
  statusCode: number;
};

 type ValidationError = {
  type: 'validation';
  message: string;
  field: string;
};

 type AppError = NetworkError | ValidationError;

function performOperation(): AppError | null {
  // Simulate either error or success
  const random = Math.random();
  if (random < 0.4) {
    return { type: 'network', message: 'Failed to reach server', statusCode: 500 };
  } else if (random < 0.8) {
    return { type: 'validation', message: 'Invalid input', field: 'email' };
  }
  return null; // no error
}

const error = performOperation();

if (error) {
  if (error.type === 'network') {
    // Here TypeScript knows error is NetworkError
    console.error(`Network error: ${error.message} (Status: ${error.statusCode})`);
  } else if (error.type === 'validation') {
    // Here TypeScript knows error is ValidationError
    console.error(`Validation failed on field '${error.field}': ${error.message}`);
  }
} else {
  console.log('Operation succeeded without errors.');
}

def count_up_to(max_value):
    count = 1
    while count <= max_value:
        yield count  # Yield the next number
        count += 1

# Using the generator
for number in count_up_to(5):
    print(number)

def read_lines(file_path):
    with open(file_path, 'r', encoding='utf-8') as file:
        for line in file:
            yield line.strip()  # Yield each line one by one, stripped of whitespace

def filter_empty(lines):
    for line in lines:
        if line:  # Skip empty lines
            yield line

def to_upper(lines):
    for line in lines:
        yield line.upper()  # Convert each line to uppercase

# Example usage
file_path = 'example.txt'  # Assume this is a large text file
pipeline = to_upper(filter_empty(read_lines(file_path)))

for processed_line in pipeline:
    print(processed_line)

